const item = $input.all()[0]?.json ?? {};
const raw = item.body ?? item;
let data = raw;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch { data = {}; } }
if (typeof data !== 'object' || data === null || Array.isArray(data)) { data = {}; }

const pick = (obj, keys, fallback) => {
  fallback = (fallback === undefined) ? '' : fallback;
  for (const key of keys) {
    const v = obj[key];
    if (v !== undefined && v !== null && String(v).trim() !== '') {
      return typeof v === 'string' ? v.trim() : String(v);
    }
  }
  return fallback;
};
const normalizePhone = (v) => {
  const digits = String(v || '').replace(/\D/g, '');
  if (!digits) return '';
  const br = (digits.startsWith('55') && digits.length > 11) ? digits.slice(2) : digits;
  const d = br.slice(0, 11);
  if (d.length === 11) return `(${d.slice(0,2)}) ${d.slice(2,7)}-${d.slice(7)}`;
  if (d.length === 10) return `(${d.slice(0,2)}) ${d.slice(2,6)}-${d.slice(6)}`;
  return d;
};
const now = new Date();
const dateBR = now.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const timeBR = now.toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit' });

const nome    = pick(data, ['Nome completo', 'nome']);
const email   = pick(data, ['E-mail', 'email', 'e-mail', 'Qual seu e-mail?']);
const wppRaw  = pick(data, ['WhatsApp', 'whatsapp', 'Qual o seu WhatsApp?']);
const wpp2Raw = pick(data, ['Confirmar WhatsApp', 'whatsapp_confirmacao', 'confirmar_whatsapp']);
const wpp     = normalizePhone(wppRaw);
const wpp2    = normalizePhone(wpp2Raw);

const channel  = pick(data, ['channel', 'canal', 'Channel']);
const source   = pick(data, ['utm_source', 'source', 'Source']);
const medium   = pick(data, ['utm_medium', 'medium', 'Medium']);
const campaign = pick(data, ['utm_campaign', 'campaign', 'Campaign']);
const content  = pick(data, ['utm_content', 'content', 'Content']);
const utmTerm  = pick(data, ['utm_term', 'Utm Term']);
const utmId    = pick(data, ['utm_id', 'Utm Id']);
const fbclid   = pick(data, ['fbclid']);
const src      = pick(data, ['src']);
const sck      = pick(data, ['sck']);
const aId      = pick(data, ['a_id']);
const referrer = pick(data, ['referrer', 'Referrer']);
const pageUrl  = pick(data, ['page_url', 'Page URL']);
const timestamp = now.toISOString();

const FUNIL = 'Tributario';
const nivelML = pick(data, ['nivel_ml','Medalha ML','Medalha no Mercado Livre']);
const regime  = pick(data, ['regime_tributario','Regime tributario','regime']);
const nL = { sem_medalha:'Sem medalha', nao_tenho:'Sem medalha', ouro:'Ouro', ouro_plus:'Ouro Plus', platinum:'Platinum', mercado_lider:'Mercado Líder' };
const rL = { mei:'MEI', simples_nacional:'Simples Nacional', lucro_presumido:'Lucro Presumido', lucro_real:'Lucro Real' };
const nivelLeg  = nL[nivelML] || nivelML;
const regimeLeg = rL[regime]  || regime;
const partes = [];
if (nivelLeg)  partes.push('Medalha ML: ' + nivelLeg);
if (regimeLeg) partes.push('Regime: ' + regimeLeg);
const pergAdic = pick(data, ['Pergunta adicional','Pergunta Adicional','pergunta_adicional'], partes.join(' | '));
const qualifiedServer = !!nivelML && nivelML !== 'sem_medalha' && nivelML !== 'nao_tenho' && !!regime && regime !== 'mei';

const mql = qualifiedServer ? 'Sim' : 'Não';
return [{ json: {
  'Data de entrada de leads': dateBR,
  'Hora':                     timeBR,
  'Nome completo':            nome,
  'E-mail':                   email,
  'WhatsApp':                 wpp,
  'Confirmar WhatsApp':       wpp2,
  'Pergunta Adicional':       pergAdic,
  Funil:                      FUNIL,
  Ingresso:                   '',
  channel:                    channel,
  Source:                     source,
  Medium:                     medium,
  Campaign:                   campaign,
  Content:                    content,
  'Utm Term':                 utmTerm,
  'Utm Id':                   utmId,
  Fbclid:                     fbclid,
  Src:                        src,
  Sck:                        sck,
  'A Id':                     aId,
  Referrer:                   referrer,
  'Page URL':                 pageUrl,
  Timestamp:                  timestamp,
  _wppDigits:                 wpp,
  MQL:                        mql
} }];

// Barra na frente qualquer chamada ao webhook (direta, sem passar pelo
// formulário) que venha sem nome, e-mail ou WhatsApp válidos. Leads
// inválidos não são descartados silenciosamente: seguem marcados para
// notificação (ver node "Lead válido?").
const lead = $input.first().json;

const nome = String(lead['Nome completo'] || '').trim();
const email = String(lead['E-mail'] || '').trim();
const wppDigits = String(lead['WhatsApp'] || '').replace(/\D/g, '');

const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
const valid = nome.length >= 3 && emailOk && wppDigits.length >= 10;

return [{ json: { ...lead, _descartado: valid ? '' : 'campos_obrigatorios_invalidos' } }];

const values = ($input.first().json.values) || [];
// values[0] é o cabeçalho ("WhatsApp"); cada linha seguinte é ["telefone"] ou [] se vazia.
return values.slice(1).map((row) => ({ json: { WhatsApp: row[0] || '' } }));

const dbRows = $input.all();
const lead   = $('Parse lead-Tributario').first().json;

const norm = (v) => {
  const d = String(v || '').replace(/\D/g, '');
  if (!d) return '';
  const br = (d.startsWith('55') && d.length > 11) ? d.slice(2) : d;
  return br.slice(0, 11);
};

const inDigits = norm(lead._wppDigits || lead['WhatsApp'] || '');

let isDuplicate = false;
if (inDigits && inDigits.length >= 8) {
  isDuplicate = dbRows.some(row => {
    const wpp = row.json['WhatsApp'] || '';
    return wpp && norm(wpp) === inDigits;
  });
}

const out = Object.fromEntries(Object.entries(lead).filter(([k]) => k !== '_wppDigits'));
return [{ json: { ...out, _descartado: isDuplicate ? 'duplicata_whatsapp' : '' } }];

const crmRows = $input.all();
const lead = $('Format lead').first().json;

const normPhone = (v) => String(v || '').replace(/\D/g, '').slice(-11);
const emailNorm = String(lead['E-mail'] || '').trim().toLowerCase();
const phoneNorm = normPhone(lead['WhatsApp']);

let match = null;
if (emailNorm) {
  match = crmRows.find(r => String(r.json['Email'] || '').trim().toLowerCase() === emailNorm);
}
if (!match && phoneNorm && phoneNorm.length >= 8) {
  match = crmRows.find(r => normPhone(r.json['Telefone 1']) === phoneNorm);
}

if (match) {
  // Lead já existe no CRM: arquiva o snapshot antigo completo (linha
  // inteira, como estava) e prepara a atualização in-place (só Funil/Data
  // de entrada/MQL/Pergunta adicional mudam; o resto do histórico
  // comercial permanece intocado).
  const when = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
  const existingQ = match.json['Pergunta adicional'] || '';
  const novaQ = lead['Pergunta Adicional'] || '';
  const mergedQ = existingQ ? `${existingQ}\n---\n[${when}] ${novaQ}` : novaQ;

  return [{ json: {
    _crmExists: true,
    _snapshotAntigo: match.json,
    Email: match.json['Email'],
    Funil: lead.Funil,
    'Data de entrada de leads': lead['Data de entrada de leads'],
    MQL: lead.MQL,
    'Pergunta adicional': mergedQ,
  } }];
}

return [{ json: { _crmExists: false, ...lead } }];

const d = $input.first().json;
// Identificação de origem orgânica (regra uniforme).
// Funil pago (lead-*) OU sinal de tráfego pago (fbclid/gclid/utm_medium pago) => 'não'; senão 'sim'.
const funil = String(d.Funil || '').trim();
const medium = String(d.Medium || '').toLowerCase();
const paidMedium = /(cpc|ppc|paid|cpm|display|paid.?social|social.?paid)/.test(medium);
const paidSignal = Boolean(d.Fbclid) || Boolean(d.Gclid) || paidMedium;
const funilPago = ['Ads','Tributario','Diagnostico','Shopee Ads'].includes(funil);
const organico = (funilPago || paidSignal) ? 'não' : 'sim';
return [{ json: {
  'Data de entrada de leads': d['Data de entrada de leads'],
  'Nomes':                    d['Nome completo'],
  'Email':                    d['E-mail'],
  'Telefone 1':               d['WhatsApp'],
  'Pergunta adicional':       d['Pergunta Adicional'],
  'Funil':                    d.Funil,
  'Orgânico?':                organico,
  'Channel':                  d.Channel,
  'Source':                   d.Source,
  'Medium':                   d.Medium,
  'Campaign':                 d.Campaign,
  'Content':                  d.Content,
  'Referrer':                 d.Referrer,
  'Page URL':                 d['Page URL'],
  'Timestamp':                d.Timestamp,
  'MQL':                      d.MQL
}}];

const d = $input.first().json;
const motivoCod = d._descartado || 'desconhecido';
const MOTIVOS = {
  campos_obrigatorios_invalidos: 'Campos obrigatórios inválidos',
  duplicata_whatsapp: 'Lead duplicado (WhatsApp já cadastrado)',
};
const motivo = MOTIVOS[motivoCod] || motivoCod;
const funil  = d.Funil || '(sem funil)';
const when   = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const nome   = d['Nome completo'] || '';
const email  = d['E-mail'] || '';
const wpp    = d['WhatsApp'] || '';
const perg   = d['Pergunta Adicional'] || '';
const origem = [d.Source, d.Medium, d.Campaign].filter(Boolean).join(' / ') || 'Direto / sem UTM';
const pagina = d['Page URL'] || '';

const row = (label, val) => `<tr><td style="padding:6px 16px 6px 0;color:#6b7280;white-space:nowrap;vertical-align:top"><b>${label}</b></td><td style="padding:6px 0;color:#111827">${(val || '—')}</td></tr>`;
const html =
  `<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;color:#111827;max-width:580px">` +
  `<p style="margin:0 0 4px">Um lead foi <b>descartado</b> pela automação e registrado na aba <b>Descarte</b> para auditoria.</p>` +
  `<p style="margin:0 0 14px;color:#6b7280">Funil: <b>${funil}</b> &nbsp;·&nbsp; Motivo: <b>${motivo}</b></p>` +
  `<table style="border-collapse:collapse;font-size:14px">` +
  row('Nome', nome) + row('E-mail', email) + row('WhatsApp', wpp) +
  row('Pergunta adicional', perg) + row('Origem (UTM)', origem) + row('Página', pagina) +
  row('Quando', when) +
  `</table></div>`;
const subject = `Lead descartado — ${motivo} — ${funil}`;

return [{ json: {
  'Data de entrada de leads': d['Data de entrada de leads'] || '',
  'Nomes':                    nome,
  'Email':                    email,
  'Telefone 1':               wpp,
  'Pergunta adicional':       perg,
  'Funil':                    funil,
  'MQL':                      d.MQL || '',
  'Channel':                  d.channel || d.Channel || '',
  'Source':                   d.Source || '',
  'Medium':                   d.Medium || '',
  'Campaign':                 d.Campaign || '',
  'Content':                  d.Content || '',
  'Referrer':                 d.Referrer || '',
  'Page URL':                 pagina,
  'Timestamp':                d.Timestamp || '',
  subject,
  html,
} }];
